    static const unsigned order[19] = {
        16, 17, 18, 0, 8, 7, 9, 6, 10, 5, 11, 4, 12, 3, 13, 2, 14, 1, 15};
    int size_only = !out;
    size_t result_size = 0;

    for (i = 0; i < 19; i++)
        clcounts[i] = 0;

    /* Trim zeros. */
    while (hlit > 0 && ll_lengths[257 + hlit - 1] == 0)
        hlit--;
    while (hdist > 0 && d_lengths[1 + hdist - 1] == 0)
        hdist--;
