            }
            if (use_17)
            {
                while (count >= 3)
                {
                    unsigned count2 = count > 10 ? 10 : count;
                    if (!size_only)
                    {
                        ZOPFLI_APPEND_DATA(17, &rle, &rle_size);
                        ZOPFLI_APPEND_DATA(count2 - 3, &rle_bits, &rle_bits_size);
                    }
                    clcounts[17]++;
                    count -= count2;
                }
            }
        }

